var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"저기……. 셰나?","JPN":"あの……シェナ？","ENG":"Um... Shena?","TWN":"那個……世娜？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"혹시 내 말 듣고 있어? 회복하느라 대답 못 하는 거야?","JPN":"聞いてる？　返事しないのは回復に集中してるから？","ENG":"Are you listening? Are you not answering because you're focusing on recovery?","TWN":"你有聽到嗎？你是因為還在恢復中，所以沒辦法回答嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"셰나, 있잖아…….","JPN":"あのね、シェナ……","ENG":"You know, Shena...","TWN":"世娜，你聽我說……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"다른 단원들이 나더러 셰나의 핵을 흡수하래.","JPN":"団員のみんなが、シェナの核を吸収しろって言うの。","ENG":"The other members told me to absorb your core.","TWN":"其他團員叫我把世娜的核心吸收到……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"조금 모자라지만 나도 그림자니까. 본능적으로 알 수 있어.","JPN":"アタシはバカでもシャドウだから。本能でわかるよ。","ENG":"I'm not that strong, but I'm still a Shadow. I can tell instinctively.","TWN":"雖然我不太聰明，但畢竟也是個暗影，所以我本能地知道，"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"지금이라면 네 핵을 차지할 수 있다고.","JPN":"今なら核を奪えるって。","ENG":"I have the power to take your core right now.","TWN":"就現在而言，我是有辦搶走你的核心的。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"그치만…. 셰나는 언제나 날 덜떨어졌다고 구박하지만.","JPN":"でもね……シェナはいつもアタシをバカだって怒るけど。","ENG":"And... you always scold me for being stupid, but.","TWN":"可是……雖然你總是說我傻，又愛欺負我。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"여태까지 지휘자님을 제일 많이 도왔는데, 다쳤다고 버려 버리는 건…….","JPN":"今までマエストロのために一番頑張ってきたシェナを、怪我したからといって捨てるのは……","ENG":"You were the most helpful one to the Chief Conductor, and to be thrown away like this just because you're hurt is...","TWN":"但是你一直是對指揮家最盡心盡力的，現在卻因為受傷就要被扔掉……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"이 느낌은…… 설마 지휘자님?","JPN":"この気配……もしかしてマエストロ？","ENG":"This feeling... Chief Conductor?","TWN":"這個感覺是……指揮家？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURRPSIE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"수, 숨어야 해! 들켰다간 또 머뭇거리냐고 한소리 듣는다구!","JPN":"か、隠れなきゃ！　バレたらまた愚図って怒られるっ！","ENG":"I-I gotta hide! She's going to scold me if she sees me lounging around!","TWN":"我…我要躲起來！要是被發現我在這，到時候又要唸我心太軟！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"셰나, 제 말이 들리나요?","JPN":"シェナ、私の声が聞こえていますか？","ENG":"Shena, can you hear me?","TWN":"世娜，你有聽到嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"……네. 그야 지휘자님의 목소리에는 늘 귀기울이고 있으니까요.","JPN":"……はい。マエストロの声には常に耳を傾けていますから。","ENG":"...Yes. I'm always paying close attention to your voice, Chief Conductor.","TWN":"……有，我一直都有聽到指揮家的聲音。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L22_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그렇군요. 제 곁으로 가까이 와 주세요.","JPN":"そうですか。私の近くに来てください。","ENG":"I see. Come closer to me.","TWN":"是嗎，到我這裡來。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"핵의 상태가 여전하군요. 이래서야 이전처럼 아름다운 음색은 뽐낼 수 없겠어요.","JPN":"核の状態は変わっていませんね。これでは以前のような美しい音色は奏でられないでしょう。","ENG":"Your core is still in bad shape. You will not be able to make the beautiful sounds you used to make before.","TWN":"你的核心依舊沒有起色，這樣就不能演奏出像之前那樣美妙的音色。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"루나는 내려오지 않았던가요?","JPN":"ルナは来ていませんか？","ENG":"Did Luna come down here?","TWN":"露娜沒有來過嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"이 시각 즈음이면 당신을 만나러 왔으리라고 예상했는데 말이에요.","JPN":"そろそろここに来ている頃だと思ったのですが。","ENG":"I expected her to come meet you around this time.","TWN":"我以為她會來找你。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"글쎄요. 지난번에 쓸데없는 걸 먹이려 하길래 내쫓았더니 그 뒤로는 잠잠하네요.","JPN":"わかりません。前に来たときに余計なものを食べさせようとするので追い出したのですが、それ以来音沙汰がありません。","ENG":"I am not sure. I haven't heard much after I kicked her out for trying to feed me something dumb.","TWN":"不知道，上次她要給我吃些莫名奇妙的東西，我把她趕走後她就沒再來吵我。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그것도 당분간이겠지만요.","JPN":"どうせまた来ると思いますが。","ENG":"I don't think it'll last long, though.","TWN":"不過應該只是暫時的。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"흐음…….","JPN":"ふーん……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그래요. 그렇군요. 상황은 이해했어요.","JPN":"そうでしたか。良くわかりました。","ENG":"Yes. I see. I understand the situation.","TWN":"是嗎？我知道了。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_LAUGH"},"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"몸소 찾아오신 이유는 루나 때문이셨나요?","JPN":"直接ここに来られたのはルナの件でですか？","ENG":"Was Luna the reason you came all the way here?","TWN":"指揮家親自造訪是要找露娜嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"후후, 그럴 리가요.","JPN":"ふふ、いいえ、まさか。","ENG":"Fu fuu, not at all.","TWN":"呵呵，怎麼會呢。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"셰나, 당신의 연주가 필요하게 되었습니다.","JPN":"シェナ、あなたの演奏が必要です。","ENG":"Your performance is required, Shena.","TWN":"世娜，我需要你的演奏。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"지휘자님의 부름은 감사하지만, 이런 꼴로 기대에 부응할 수 있을까요?","JPN":"マエストロのご指名は嬉しいのですが、この状態の私がご期待に添えるでしょうか？","ENG":"I appreciate your invitation, but will I be able to live up to your expectations in this state?","TWN":"謝謝指揮家的抬舉，但我現在這副模樣，還有辦法滿足你的期待嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그만큼 신뢰한다는 뜻이지요.","JPN":"それだけ信頼しているのですよ。","ENG":"I have faith in you.","TWN":"這說明我非常信任你。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"당신이 여기 머무는 동안, 카르멘이 <color=#ffd34c>가시</color>를 빼내는 일에 자원했답니다.","JPN":"あなたがここにいる間、カルメンが<color=#ffd34c>トゲ</color>を抜く仕事に志願しました。","ENG":"While you were here, Carmen volunteered for the task of extracting the <color=#ffd34c>thorn</color>.","TWN":"你待在這裡的這段時間，卡門自願參加<color=#ffd34c>拔刺</color>的任務。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"카르멘이 말인가요?","JPN":"カルメンが、ですか？","ENG":"Carmen?","TWN":"卡門？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"의외네요. 보통 이럴 때는 앞장 서서 꽁지를 말고 숨는 편이었는데.","JPN":"意外ですね。今までならこういう時は一番先に逃げ出すタイプなのに。","ENG":"That's strange. She usually hid with her tail between her legs in situations like this.","TWN":"真令人意外，通常她遇到這種事都是第一個躲起來的。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"그래요. 카르멘의 연주 솜씨는 나무랄 데 없지만, 다소 제멋대로인 경향이 강하니.","JPN":"そうですね。カルメンの演奏はこの上なく素晴らしいのですが、少し自己中心的過ぎますから。","ENG":"Yes, Carmen's performance is satisfactory, but she does have a tendency to run off on her own.","TWN":"沒錯，卡門的演奏技巧雖然無可挑剔，但就是太任意妄為。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"당신이라면 제 말뜻을 이해하겠죠, 셰나.","JPN":"あなたなら私の言うことがわかりますよね、シェナ。","ENG":"I am sure you understand what I mean, Shena.","TWN":"你應該明白我的意思吧，世娜。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"루이제 슈나이더를 확보하길 원하시는 걸까요?","JPN":"ルイーゼ・シュナイダーを確保すればいいのでしょうか？","ENG":"Would you like me to procure Louise Schneider?","TWN":"指揮家是想要我去找露易絲·修奈德嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"하지만 조금 곤란한 걸요.","JPN":"しかし、成し遂げられるかどうか。","ENG":"But it is troublesome.","TWN":"這恐怕有點困難。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그 늙은이에게 눈독을 들이는 자들이 당장 머릿속에 떠오르는 것만도 여럿 되니까요.","JPN":"あの老婆に目をつけている連中が、すぐに思いつくだけでも何人もいます。","ENG":"I know of several individuals who are interested in that old human.","TWN":"畢竟現在一堆人都在找那個老太婆。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"루나를 데려가도록 하세요. 부족하지만 유사시에는 도움이 되겠지요.","JPN":"ルナを連れていくといいでしょう。あの子でもいざというときは役に立つはずです。","ENG":"Take Luna with you. She is not up to par, but she will be able to assist in times of need.","TWN":"你可以帶露娜一起去，她有她的缺點，但應該還是可以幫上你。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"네. 제가 어떻게 마다하겠어요.","JPN":"はい、わかりました。","ENG":"Of course. How could I defy you?","TWN":"是，我不敢違抗指揮家之命。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"모두, 지휘자님의 뜻대로.","JPN":"すべてはマエストロの御心のままに。","ENG":"Your wish is my command, Chief Conductor.","TWN":"都照指揮家的意思。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후우…….","JPN":"ふう……","ENG":"*Sigh...*","TWN":"呼……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"거기 숨어 있는 거 다 알고 있어, 루나.","JPN":"そこに隠れているの知っているわよ、ルナ。","ENG":"I know you're hiding there, Luna.","TWN":"我知道你躲在那裡，露娜。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"얼른 기어나와. 머저리 같으니라고.","JPN":"早く出てきなさい、まぬけ。","ENG":"Come out now, idiot.","TWN":"還不給我出來，你這個笨蛋。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"푸하아! 하아, 하아!","JPN":"ぷはっ！　はぁ、はぁ！","ENG":"Paaah! *Huff* *Huff*","TWN":"噗哈！呼呼，呼呼！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L12_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"어, 어떻게 알았어? 침식파도 숨도 꾹 참았는데….","JPN":"な、なんでわかったの？　侵食波も息もぐっと堪えていたのに……","ENG":"H-how did you know? I held my Corruption ray and my breath...","TWN":"你…你怎麼知道的？我連侵蝕波都藏起來咧…"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그야 모를 리 없지. 처음부터 얼쩡거리는 네가 귀찮아서 대답하지 않았던 거니까.","JPN":"わからないわけないでしょ。最初からうろうろするあなたが面倒で無視していただけだしね。","ENG":"Of course I knew. I only refused to answer because you were being a bother.","TWN":"怎麼可能不知道。我不回答是因為懶得搭理你。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"너, 너무해! 그럼 내가 했던 말도 다 들었단 뜻이잖아!","JPN":"ひ、酷い！　じゃあアタシが言ったことも全部聞いていたってこと？","ENG":"W-what?! That means, you heard everything I said!","TWN":"好…好過分！所以我說的話你都有聽見囉！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그래. 너도 참 운이 좋더라.","JPN":"ええ。それにしても、運がよかったわね。","ENG":"Yeah. You're quite lucky, too.","TWN":"對，算你運氣好。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"만약 내 악기를 건드렸으면 손목부터 날려 버릴 예정이었거든.","JPN":"もし私の楽器に触れたら、手首を吹き飛ばそうと思っていたのに。","ENG":"I was going to blow your wrist off if you tried to touch my instrument.","TWN":"剛才你要是敢碰我的樂器，我一定會砍掉你的手。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"아아, 아, 안 만졌어! 털끝만큼도 안 건드렸다구!","JPN":"え、さ、触ってない！　これっぽちも触ってないよ！","ENG":"I-I-I d-didn't touch it! Not even a bit!","TWN":"沒沒沒，我沒碰！完全沒碰到！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"……흥. 겁쟁이에다 바보구나. 정말.","JPN":"……はあ。怖がりなうえにバカとはね。まったく。","ENG":"...Hmph. A fool and a coward.","TWN":"……哼，看來你不只笨還很膽小。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"너 따위가 정말 빌어야 할 건 그게 아니지 않아?","JPN":"あなたが本当に許しを請うべきなのは、私じゃないでしょ？","ENG":"That's not what you should be focusing on.","TWN":"你真正該求饒的不是這件事吧？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"지휘자님의 의중을 함부로 헤아리다니, 역시 짐승으로 살고 싶은가 보네.","JPN":"マエストロの意を察しようとするなんて、やっぱり獣として生きていきたいみたいね。","ENG":"I guess you're okay with becoming a filthy beast, seeing how you're making assumptions about the Chief Conductor's will.","TWN":"竟敢擅自揣測指揮家的心思，看來是真想變成畜生。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"히익…! 맞다……!","JPN":"ひいっ……！　そうだった……！","ENG":"Eeep...! Right...!","TWN":"嗚……！拜託……！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"비밀로 해 줘, 셰나! 응? 내가 뭐든지 할 테니까!","JPN":"内緒にして、ね？　シェナ。なんでもするから！","ENG":"Please keep it a secret, Shena! Please? I'll do anything!","TWN":"一定要替我保密，世娜！好不好？我會好好聽你的話！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그래. 알겠으면 얌전히 내가 시키는 대로 하기나 해.","JPN":"わかった。なら大人しく私の言う通りにしなさい。","ENG":"Fine. Do as I say, if you know what's good for you.","TWN":"很好。那你就乖乖聽從我的指示。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"지휘자님께 말씀드릴지, 말지는 네 태도를 봐서 결정할 테니까.","JPN":"マエストロに言いつけるかどうかは、あなたの態度次第で決めるわ。","ENG":"I might or might not tell the Chief Conductor, based on your behavior.","TWN":"我會看你的態度，再決定要不要告訴指揮家。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"으으……. 망했어……. 망했다구…….","JPN":"うう……もうダメだ……終わった……","ENG":"Ngh... I'm screwed... I'm so screwed...","TWN":"呃呃……我慘了……完蛋……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"}]`);export{e as default};